/// Normalize a free-form skill label into a lookup key.
/// "Rust (Axum)" → "rust", "BLE (MDS, Nordic)" → "ble",
/// "Node.js (Express)" → "nodejs", "Migration: XML+Java → Kotlin+Compose"
/// → "migrationxmljavakotlincompose".
String _normalize(String label) {
  // Strip any (parenthetical) groups first.
  final noParens = label.replaceAll(RegExp(r'\([^)]*\)'), '');
  return noParens
      .toLowerCase()
      .replaceAll(RegExp(r'[\s/.\-+:&,→•]'), '')
      .replaceAll(RegExp(r'[^a-z0-9]'), '');
}

/// Returns the inline SVG markup for [label], or null if no match.
/// The caller (SkillBadge) should render a fallback glyph for null.
String? iconFor(String label) {
  final key = _normalize(label);
  return _icons[key];
}
